@startuml
skinparam shadowing false
skinparam backgroundColor white
skinparam defaultTextAlignment left

skinparam rectangle {
  BackgroundColor #E6E6E6
  BorderColor #666666
  RoundCorner 12
}

skinparam package {
  BackgroundColor #E6E6E6
  BorderColor #666666
}

rectangle "Test System" as TS

package "Engine under Test" as EUT {
  rectangle "Process Instance" as PI
  rectangle " " as X
}

TS -[hidden]down- PI

TS --> PI : send input
PI ..> TS : receive observable output

PI -down- X
X : X
hide X stereotype
@enduml
